// Minimal FullCalendar stub used as a local fallback when CDN is unavailable.
// Implements the small subset of API the app uses: `new FullCalendar.Calendar(el, opts)`,
// `render()`, `removeAllEvents()`, `addEvent(ev)`, `setOption(name, value)`, and a `view`
// object with `activeStart`/`activeEnd` dates. This is NOT a full replacement — it's
// intended to provide basic visualization of background events (blocked days) so the
// scheduling UI remains usable offline.
(function (window) {
  function startOfDay(d) {
    const x = new Date(d);
    x.setHours(0, 0, 0, 0);
    return x;
  }

  function Calendar(el, options) {
    this.el = el;
    this.options = options || {};
    this._events = [];
    // default view range: current week
    const now = new Date();
    now.setHours(0, 0, 0, 0);
    this.view = {
      activeStart: new Date(now),
      activeEnd: new Date(now.getTime() + 7 * 24 * 60 * 60 * 1000),
      title: new Date(now).toLocaleString(undefined, {
        month: "long",
        year: "numeric",
      }),
    };
    this._onEventClick = this.options.eventClick || function () {};
  }

  Calendar.prototype.render = function () {
    this.el.innerHTML = "";
    const header = document.createElement("div");
    header.style.padding = "8px 12px";
    header.style.fontWeight = "700";
    header.textContent = this.options.initialView || "timeGridWeek";
    this.el.appendChild(header);

    // render month or week grid depending on requested view
    const viewName =
      this.options.initialView || this.options.view || "timeGridWeek";
    const container = document.createElement("div");

    // group events by date (ISO YYYY-MM-DD)
    const bg = this._events.filter(
      (e) =>
        e.display === "background" ||
        e.allDay ||
        (e.extendedProps && e.extendedProps.background),
    );
    const byDate = {};
    bg.forEach((ev) => {
      const d = new Date(ev.start).toISOString().slice(0, 10);
      byDate[d] = byDate[d] || [];
      byDate[d].push(ev);
    });

    // helper to pick priority color: non-working (gray) > booked (red) > working (green)
    function pickColorForEvents(events) {
      if (!events || events.length === 0) return null;
      for (let e of events) {
        if (e.backgroundColor) return e.backgroundColor;
        if (e.color) return e.color;
        if (e.extendedProps && e.extendedProps.color)
          return e.extendedProps.color;
      }
      for (let e of events) {
        const ex = e.extendedProps || {};
        if (ex.nonWorking || ex.holiday || ex.reason) return "#6c757d";
      }
      for (let e of events) {
        const ex = e.extendedProps || {};
        if (ex.status && ex.status.toString().toLowerCase().includes("book"))
          return "#dc3545";
      }
      for (let e of events) {
        if (e.title && /booked/i.test(e.title)) return "#dc3545";
      }
      return "#28a745";
    }

    // convert hex (#rrggbb) to rgba string with supplied alpha; passthrough for rgba inputs
    function colorToBackground(color, alpha) {
      if (!color) return null;
      color = String(color).trim();
      if (color.indexOf("rgba(") === 0) return color;
      if (color.indexOf("rgb(") === 0)
        return color
          .replace("rgb(", "rgba(")
          .replace(")", "," + (alpha || 0.12) + ")");
      // hex -> rgba
      const hex = color.replace("#", "");
      if (hex.length === 3) {
        const r = parseInt(hex[0] + hex[0], 16);
        const g = parseInt(hex[1] + hex[1], 16);
        const b = parseInt(hex[2] + hex[2], 16);
        return `rgba(${r},${g},${b},${alpha || 0.12})`;
      }
      if (hex.length === 6) {
        const r = parseInt(hex.slice(0, 2), 16);
        const g = parseInt(hex.slice(2, 4), 16);
        const b = parseInt(hex.slice(4, 6), 16);
        return `rgba(${r},${g},${b},${alpha || 0.12})`;
      }
      return color;
    }

    // helper to format like "Mon Feb 16 2026"
    function formatLabel(d) {
      const days = ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"];
      const months = [
        "Jan",
        "Feb",
        "Mar",
        "Apr",
        "May",
        "Jun",
        "Jul",
        "Aug",
        "Sep",
        "Oct",
        "Nov",
        "Dec",
      ];
      return (
        days[d.getDay()] +
        " " +
        months[d.getMonth()] +
        " " +
        d.getDate() +
        " " +
        d.getFullYear()
      );
    }

    if (viewName === "dayGridMonth" || viewName.indexOf("dayGrid") === 0) {
      container.className = "fc-month-grid";
      // determine month to show
      let ref = this.options.initialDate
        ? new Date(this.options.initialDate)
        : this.view && this.view.activeStart
          ? new Date(this.view.activeStart)
          : new Date();
      const year = ref.getFullYear();
      const month = ref.getMonth();
      const firstOfMonth = new Date(year, month, 1);
      firstOfMonth.setHours(0, 0, 0, 0);
      // calendar grid start: Sunday on/before firstOfMonth
      const start = new Date(firstOfMonth);
      start.setDate(start.getDate() - start.getDay());
      // calendar grid end: Saturday on/after last day
      const lastOfMonth = new Date(year, month + 1, 0);
      lastOfMonth.setHours(0, 0, 0, 0);
      const end = new Date(lastOfMonth);
      end.setDate(end.getDate() + (6 - end.getDay()));

      // update view title for compatibility with real FullCalendar
      try {
        this.view = this.view || {};
        this.view.activeStart = new Date(ref);
        this.view.activeEnd = new Date(end);
        this.view.title = new Date(ref).toLocaleString(undefined, {
          month: "long",
          year: "numeric",
        });
      } catch (e) {}

      // build header row (Sun..Sat)
      const headerRow = document.createElement("div");
      headerRow.className = "fc-month-header";
      ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"].forEach((dn) => {
        const h = document.createElement("div");
        h.className = "fc-month-header-cell";
        h.textContent = dn;
        headerRow.appendChild(h);
      });
      container.appendChild(headerRow);

      // iterate weeks
      let cur = new Date(start);
      while (cur <= end) {
        const weekRow = document.createElement("div");
        weekRow.className = "fc-month-week";
        for (let i = 0; i < 7; i++) {
          const cell = document.createElement("div");
          cell.className = "fc-month-cell";
          const dateNum = document.createElement("div");
          dateNum.className = "fc-day-number";
          dateNum.textContent = cur.getDate();
          cell.appendChild(dateNum);
          const key = cur.toISOString().slice(0, 10);
          const eventsHere = byDate[key] || [];
          const color = pickColorForEvents(eventsHere);
          // apply subtle translucent background and badges instead of full solid fill
          if (color) {
            const bg = colorToBackground(color, 0.12);
            try {
              cell.style.background = bg;
            } catch (e) {
              cell.style.background = color;
            }
            // dim text for readability when background is light translucent; keep default text color
            cell.classList.add("fc-has-bg");
            // add small badges for important markers (holiday/rest/booked)
            const badges = document.createElement("div");
            badges.className = "fc-cell-badges";
            eventsHere.slice(0, 2).forEach((ev) => {
              const b = document.createElement("span");
              b.className = "fc-event-badge";
              b.textContent = ev.title || "";
              if ((ev.title || "").toLowerCase().includes("holiday"))
                b.style.background = "rgba(107,114,128,0.18)";
              else if ((ev.title || "").toLowerCase().includes("rest"))
                b.style.background = "rgba(255,193,7,0.12)";
              else if ((ev.title || "").toLowerCase().includes("available"))
                b.style.background = "rgba(16,185,129,0.12)";
              badges.appendChild(b);
            });
            cell.appendChild(badges);
          }
          // mark days outside the current month
          if (cur.getMonth() !== month)
            cell.classList.add("fc-month-cell-outside");
          weekRow.appendChild(cell);
          cur = new Date(cur.getTime() + 24 * 60 * 60 * 1000);
        }
        container.appendChild(weekRow);
      }

      this.el.appendChild(container);
      return;
    }

    // fallback list view
    const listBg = this._events.filter(
      (e) => e.display === "background" || e.allDay,
    );
    if (listBg.length === 0) {
      const none = document.createElement("div");
      none.className = "fc-empty";
      none.textContent = "No calendar events";
      container.appendChild(none);
    } else {
      // group by date string
      const byDate2 = {};
      listBg.forEach((ev) => {
        const k = new Date(ev.start).toISOString().slice(0, 10);
        byDate2[k] = byDate2[k] || [];
        byDate2[k].push(ev);
      });
      Object.keys(byDate2)
        .sort()
        .forEach((dateKey) => {
          const dayWrap = document.createElement("div");
          dayWrap.className = "fc-day";
          const dayLabel = document.createElement("div");
          dayLabel.className = "fc-day-label";
          dayLabel.textContent = new Date(dateKey).toDateString();
          dayWrap.appendChild(dayLabel);
          byDate2[dateKey].forEach((ev) => {
            const item = document.createElement("div");
            item.className = "fc-event";
            item.textContent = ev.title || ev.id || "Event";
            item.addEventListener("click", () => {
              try {
                this._onEventClick({ event: { extendedProps: ev } });
              } catch (e) {}
            });
            dayWrap.appendChild(item);
          });
          container.appendChild(dayWrap);
        });
    }
    this.el.appendChild(container);
  };

  Calendar.prototype.removeAllEvents = function () {
    this._events = [];
    if (this.el) this.render();
  };
  Calendar.prototype.addEvent = function (ev) {
    this._events.push(ev);
    if (this.el) this.render();
  };
  Calendar.prototype.setOption = function (name, value) {
    this.options[name] = value;
    if (name === "businessHours") {
      /* ignored for fallback */
    }
  };

  // mimic a few convenience methods from real FullCalendar
  Calendar.prototype.getDate = function () {
    return this.view && this.view.activeStart
      ? new Date(this.view.activeStart)
      : new Date();
  };
  Calendar.prototype.next = function () {
    const viewName =
      (this.options && (this.options.initialView || this.options.view)) ||
      "dayGridMonth";
    const ref =
      this.view && this.view.activeStart
        ? new Date(this.view.activeStart)
        : new Date();
    const next = new Date(ref);
    if (String(viewName).toLowerCase().includes("month"))
      next.setMonth(next.getMonth() + 1);
    else next.setDate(next.getDate() + 7);
    // update view range
    this.view.activeStart = new Date(next);
    this.view.activeEnd = new Date(
      next.getTime() +
        (String(viewName).toLowerCase().includes("month") ? 32 : 7) *
          24 *
          60 *
          60 *
          1000,
    );
    if (this.options)
      this.options.initialDate = this.view.activeStart
        .toISOString()
        .slice(0, 10);
    if (this.el) this.render();
  };
  Calendar.prototype.prev = function () {
    const viewName =
      (this.options && (this.options.initialView || this.options.view)) ||
      "dayGridMonth";
    const ref =
      this.view && this.view.activeStart
        ? new Date(this.view.activeStart)
        : new Date();
    const prev = new Date(ref);
    if (String(viewName).toLowerCase().includes("month"))
      prev.setMonth(prev.getMonth() - 1);
    else prev.setDate(prev.getDate() - 7);
    this.view.activeStart = new Date(prev);
    this.view.activeEnd = new Date(
      prev.getTime() +
        (String(viewName).toLowerCase().includes("month") ? 32 : 7) *
          24 *
          60 *
          60 *
          1000,
    );
    if (this.options)
      this.options.initialDate = this.view.activeStart
        .toISOString()
        .slice(0, 10);
    if (this.el) this.render();
  };

  // emulate FullCalendar.gotoDate(date)
  Calendar.prototype.gotoDate = function (date) {
    const d = new Date(date);
    const viewName =
      (this.options && (this.options.initialView || this.options.view)) ||
      "dayGridMonth";
    if (String(viewName).toLowerCase().includes("month")) {
      const first = new Date(d.getFullYear(), d.getMonth(), 1);
      first.setHours(0, 0, 0, 0);
      const last = new Date(d.getFullYear(), d.getMonth() + 1, 0);
      last.setHours(23, 59, 59, 999);
      this.view.activeStart = first;
      this.view.activeEnd = new Date(last.getTime() + 24 * 60 * 60 * 1000);
    } else {
      // align to week containing date (Sunday start)
      const s = new Date(d);
      s.setHours(0, 0, 0, 0);
      s.setDate(s.getDate() - s.getDay());
      this.view.activeStart = s;
      this.view.activeEnd = new Date(s.getTime() + 7 * 24 * 60 * 60 * 1000);
    }
    if (this.options)
      this.options.initialDate = this.view.activeStart
        .toISOString()
        .slice(0, 10);
    if (this.el) this.render();
  };

  // expose global
  window.FullCalendar = window.FullCalendar || {};
  window.FullCalendar.Calendar = Calendar;
})(window);
